","interface StatsResult {
 totalDonors: number;
 bloodUnitsAvailable: number;
 activeRequests: number;
 scheduledAppointments: number;
 lowStockAlerts: number;
 completedDonations: number;
}

const headers = {
 "X-UserToken": (window as any).g_ck,
 Accept: "application/json",
};

async function getCount(table: string, query?: string): Promise<number> {
 let url = `/api/now/stats/${table}?sysparm_count=true`;
 if (query) {
 url += `&sysparm_query=${encodeURIComponent(query)}`;
 }
 const res = await fetch(url, { headers });
 const data = await res.json();
 return parseInt(data.result.stats.count, 10) || 0;
}

async function getSum(table: string, field: string, query?: string): Promise<number> {
 let url = `/api/now/stats/${table}?sysparm_sum_fields=${field}`;
 if (query) {
 url += `&sysparm_query=${encodeURIComponent(query)}`;
 }
 const res = await fetch(url, { headers });
 const data = await res.json();
 const sum = data.result.stats.sum?.[field];
 return parseInt(sum, 10) || 0;
}

export async function getTotalDonors(): Promise<number> {
 return getCount("x_1920732_lifeli_0_donor_profile");
}

export async function getBloodUnitsAvailable(): Promise<number> {
 return getSum("x_1920732_lifeli_0_blood_inventory", "units_available");
}

export async function getActiveRequests(): Promise<number> {
 return getCount("x_1920732_lifeli_0_blood_request", "stateIN1,2");
}

export async function getScheduledAppointments(): Promise<number> {
 return getCount("x_1920732_lifeli_0_appointment", "appointment_status=scheduled");
}

export async function getLowStockAlerts(): Promise<number> {
 return getCount("x_1920732_lifeli_0_blood_inventory", "units_available<=5");
}

export async function getCompletedDonations(): Promise<number> {
 return getCount("x_1920732_lifeli_0_donation_history", "donation_status=completed");
}

export async function getAllStats(): Promise<StatsResult> {
 const [
 totalDonors,
 bloodUnitsAvailable,
 activeRequests,
 scheduledAppointments,
 lowStockAlerts,
 completedDonations,
 ] = await Promise.all([
 getTotalDonors(),
 getBloodUnitsAvailable(),
 getActiveRequests(),
 getScheduledAppointments(),
 getLowStockAlerts(),
 getCompletedDonations(),
 ]);
 return {
 totalDonors,
 bloodUnitsAvailable,
 activeRequests,
 scheduledAppointments,
 lowStockAlerts,
 completedDonations,
 };
}
