","import React, { useState, useEffect } from "react";
import "./app.css";
import Header from "./components/Header";
import KpiCard from "./components/KpiCard";
import QuickLinks from "./components/QuickLinks";
import { getAllStats } from "./services/DashboardService";

interface Stats {
 totalDonors: number;
 bloodUnitsAvailable: number;
 activeRequests: number;
 scheduledAppointments: number;
 lowStockAlerts: number;
 completedDonations: number;
}

export default function App() {
 const [stats, setStats] = useState<Stats | null>(null);
 const [loading, setLoading] = useState(true);

 useEffect(() => {
 getAllStats()
 .then((data) => setStats(data))
 .catch((err) => console.error("Failed to load stats:", err))
 .finally(() => setLoading(false));
 }, []);

 if (loading) {
 return (
 <div className="ll-app">
 <Header />
 <main className="ll-main">
 <div className="ll-loading">Loading dashboard data...</div>
 </main>
 </div>
 );
 }

 return (
 <div className="ll-app">
 <Header />
 <main className="ll-main">
 <h2 className="ll-section-title">Overview</h2>
 <div className="ll-kpi-grid">
 <KpiCard icon="👥" value={stats?.totalDonors ?? 0} label="Total Donors" color="#D32F2F" />
 <KpiCard icon="🩸" value={stats?.bloodUnitsAvailable ?? 0} label="Blood Units Available" color="#1976D2" />
 <KpiCard icon="📋" value={stats?.activeRequests ?? 0} label="Active Requests" color="#FB8C00" />
 <KpiCard icon="📅" value={stats?.scheduledAppointments ?? 0} label="Today's Appointments" color="#43A047" />
 <KpiCard icon="⚠️" value={stats?.lowStockAlerts ?? 0} label="Low Stock Alerts" color="#C62828" />
 <KpiCard icon="✅" value={stats?.completedDonations ?? 0} label="Completed Donations" color="#43A047" />
 </div>
 <QuickLinks />
 </main>
 </div>
 );
}
